INSERT INTO questao (id, pergunta, alternativa_a, alternativa_b, alternativa_c, alternativa_d, alternativa_e, resposta_correta, disciplina, peso) VALUES
('1', 'Deixe a seriedade para as horas em que ela é inevitável: mortes, separações, dores e afins. No dia a dia, pelo amor de Deus, seja idiota! Ria dos próprios defeitos. E de quem acha defeitos em você.', 'O adjetivo inevitável pode ser substituído por inexorável.', 'O pronome relativo em que pode ser substituído por onde.', 'A expressão adverbial No dia a dia está com vírgula.', 'O termo próprios está em desacordo com as regras de concordância.', 'Os verbos deixar e rir estão no presente do subjuntivo.', 'A', 'CLPAP', 1.0),
('2', 'A ONU estima que existam 250 milhões de expatriados no mundo, entre legalizados e ilegais. E, se dependesse apenas da vontade das pessoas, esse número poderia ser ainda maior.', 'Sem-teto, bio-ritmo, semi-círculo.', 'Aquém-mar, manda-chuva, super-aquecimento.', 'Pré-vestibular, inter-estelar, ultra-resistente.', 'Ex-aluno, sem-terra, pós-doutorado.', 'Anti-higiênico, infra-estrutura, sub-emprego.', 'D', 'CLPAP', 1.0),
('3', 'Quanto a normas gramaticais da escrita padrão, relativas às concordâncias, analise as afirmativas.', 'III e IV, apenas.', 'I, III e IV, apenas.', 'II, III e V, apenas.', 'I, II, IV e V, apenas.', 'I, II e V, apenas.', 'E', 'CLPAP', 1.0),
('4', 'Sobre o texto, marque V para as afirmativas verdadeiras e F para as falsas.', 'V, V, F, F', 'V, F, V, V', 'F, F, V, V', 'F, V, F, F', 'V, F, F, V', 'B', 'CLPAP', 1.0),
('5', 'A respeito de recursos linguísticos e semânticos empregados no texto, assinale a afirmativa INCORRETA.', 'A repetição da palavra média sugere espanto do autor.', 'A primeira frase pode ser reescrita sem prejuízo.', 'O advérbio de modo acrescenta ideia de linearidade.', 'Petizada significa grupo de crianças, garotada.', 'A relação de coordenação expressa oposição.', 'C', 'CLPAP', 1.0),
('6', 'Você sabe quanto está sua pressão arterial?', 'O pronome la retoma o sentido de pressão.', 'A primeira frase refere-se ao ato de medir a pressão.', 'A última frase refere-se ao ato de medir a pressão.', 'Alimentação adequada, exercícios e medicamentos são cogitados.', 'Os 31% remetem aos 100% dos participantes.', 'E', 'CLPAP', 1.0),
('7', 'Na tira, há três palavras homófonas heterográficas: cestas, sestas e sextas.', 'Há exemplo de antonímia.', 'Há exemplo de homonímia perfeita.', 'Há exemplo de sinonímia.', 'Há exemplo de conotação.', 'Há exemplo de homonímia homográfica.', 'D', 'CLPAP', 1.0),
